287→                (psi as LeafElement).rawInsertBeforeMe(psiWhiteSpace)
288→            }
289→        }
290→    } else {
291→        val prevLeaf =
292→            requireNotNull(prevLeaf()) {
293→                "Can not upsert a whitespace if the first node is a non-leaf node"
294→            }
295→        prevLeaf.upsertWhitespaceAfterMe(text)
