    fun `indentation after wrapping inside a raw string`() {
        val code =
            """
            val q = $MULTILINE_STRING_QUOTE
                line1
                $.{query.gameId?.let { "AND id = ?" } ?: ""}
            $MULTILINE_STRING_QUOTE
            """.trimIndent().replace("$.", "$")
        // Even with a very small max line length, it should not wrap because it's inside a string template
        wrappingRuleAssertThat(code)
            .withEditorConfigOverride(com.pinterest.ktlint.core.api.editorconfig.MAX_LINE_LENGTH_PROPERTY to 10)
            .hasNoLintViolations()
